import {
    Commitment,
    PublicKey,
    type Connection,
    Transaction,
    TransactionInstruction,
    SystemProgram,
} from '@solana/web3.js'
import { ClawlabProgram } from './program'

import {
    type PoolConfig,
    type Config,

    CreateParams,
    MintToParams,
    RefundParams,
    InitializePoolParameters,
    BuyTokenParameters,
    BuyTokenAccounts,
} from '../types'

import {
    derivePool,
    deriveBaseVault,
    deriveQuoteVault,
    deriveMintMetadata,
    deriveUserTokenAccount,
    unwrapSOLInstruction,
    wrapSOLInstruction,
    getOrCreateATAInstruction,
} from '../helpers'

import {
    CLAWLAB_PROGRAM_ID,
    METAPLEX_PROGRAM_ID,
} from '../constants'

import { NATIVE_MINT } from '@solana/spl-token'
import { TOKEN_PROGRAM_ID } from '@solana/spl-token'
import { StateService } from './state'
import BN from 'bn.js'

export class PoolService extends ClawlabProgram {
    private state: StateService

    constructor(connection: Connection) {
        super(connection)
        this.state = new StateService(connection)
    }

    private async initializePoolIx(
        payer: PublicKey,
        baseMint: PublicKey,
        quoteMint: PublicKey,
        params: InitializePoolParameters,
    ): Promise<TransactionInstruction> {

        const poolAddress = derivePool(baseMint, quoteMint);

        const baseVault = deriveBaseVault(baseMint, this.config);

        const quoteVault = deriveQuoteVault(quoteMint, this.config);

        const mintMetadata = deriveMintMetadata(baseMint);

        return this.program.methods
            .initializeSplPool(params)
            .accountsPartial({
                poolAuthority: this.poolAuthority,
                config: this.config,
                baseMint: baseMint,
                quoteMint: quoteMint,
                pool: poolAddress,
                baseVault: baseVault,
                quoteVault: quoteVault,
                mintMetadata: mintMetadata,
                metadataProgram: METAPLEX_PROGRAM_ID,
                tokenBaseProgram: TOKEN_PROGRAM_ID,
                tokenQuoteProgram: TOKEN_PROGRAM_ID,
                payer: payer,
                systemProgram: SystemProgram.programId,
                eventAuthority: this.eventAuthority,
                program: CLAWLAB_PROGRAM_ID,
            })
            .instruction()
    }

    async CreateIx(payer: PublicKey,
        baseMint: PublicKey,
        quoteMint: PublicKey,
        params: InitializePoolParameters,
    ): Promise<TransactionInstruction> {
        return this.initializePoolIx(
            payer, 
            baseMint, 
            quoteMint,
            params,
        )
    }

    async CreateTx(params: CreateParams): Promise<Transaction> {

        const {
            payer,
            baseMint,
            ...initializeParam
        } = params

        const quoteMint = NATIVE_MINT;

        const createPoolIx = await this.initializePoolIx(payer, baseMint, quoteMint, initializeParam)

        return new Transaction().add(createPoolIx)
    }

    private async buyTokenIx(
        payer: PublicKey,
        baseMint: PublicKey,
        quoteMint: PublicKey,
        inputTokenAccount: PublicKey,
        outputTokenAccount: PublicKey,
        userTokenAccount: PublicKey,
        params: BuyTokenParameters,
    ): Promise<TransactionInstruction> {

        const poolAddress = derivePool(baseMint, quoteMint);

        const baseVault = deriveBaseVault(baseMint, this.config);

        const quoteVault = deriveQuoteVault(quoteMint, this.config);

        return this.program.methods
            .buyToken(params)
            .accountsPartial({
                poolAuthority: this.poolAuthority,
                config: this.config,
                baseMint: baseMint,
                quoteMint: quoteMint,
                pool: poolAddress,
                baseVault: baseVault,
                quoteVault: quoteVault,
                inputTokenAccount: inputTokenAccount,
                outputTokenAccount: outputTokenAccount,
                userTokenAccount: userTokenAccount,
                payer: payer,
                tokenBaseProgram: TOKEN_PROGRAM_ID,
                tokenQuoteProgram: TOKEN_PROGRAM_ID,
                systemProgram: SystemProgram.programId,
                eventAuthority: this.eventAuthority,
                program: CLAWLAB_PROGRAM_ID,
            } as BuyTokenAccounts)
            .instruction()
    }

    async MintToIx(payer: PublicKey,
        baseMint: PublicKey,
        quoteMint: PublicKey,
        inputTokenAccount: PublicKey,
        outputTokenAccount: PublicKey,
        userTokenAccount: PublicKey,
        params: BuyTokenParameters,
    ): Promise<TransactionInstruction> {
        return this.buyTokenIx(
            payer,
            baseMint,
            quoteMint,
            inputTokenAccount,
            outputTokenAccount,
            userTokenAccount,
            params,
        )
    }

    async MintToTx(params: MintToParams): Promise<Transaction> {

        const {
            payer,
            baseMint,
            ...mintToParam
        } = params

        const quoteMint = NATIVE_MINT;

        const preInstructions: TransactionInstruction[] = []
        const postInstructions: TransactionInstruction[] = []

        const userTokenAccount = deriveUserTokenAccount(baseMint, payer);

        const { ataPubkey: quoteMintAta, ix: createQuoteMintAtaIx } = await getOrCreateATAInstruction(
            this.connection,
            quoteMint,
            payer,
            payer,
            true,
            TOKEN_PROGRAM_ID,
        );

        createQuoteMintAtaIx && preInstructions.push(createQuoteMintAtaIx)

        const amountIn = params.copies.mul(new BN(200_000_000))
        
        preInstructions.push(...wrapSOLInstruction(payer, quoteMintAta, BigInt(amountIn.toString())))

        const { ataPubkey: baseMintAta, ix: createBaseMintAtaIx } = await getOrCreateATAInstruction(
            this.connection,
            baseMint,
            payer,
            payer,
            true,
            TOKEN_PROGRAM_ID,
        );

        createBaseMintAtaIx && preInstructions.push(createBaseMintAtaIx)

        const mintToIx = await this.buyTokenIx(
            payer,
            baseMint,
            quoteMint,
            quoteMintAta,
            baseMintAta,
            userTokenAccount,
            mintToParam,
        )

        const unwrapSolIx = unwrapSOLInstruction(payer, payer)
        unwrapSolIx && postInstructions.push(unwrapSolIx)

        return new Transaction().add(...preInstructions, mintToIx, ...postInstructions)
    }

    private async refundTokenIx(
        payer: PublicKey,
        baseMint: PublicKey,
        quoteMint: PublicKey,
        userTokenAccount: PublicKey,
        outputTokenAccount: PublicKey,
    ): Promise<TransactionInstruction> {

        const poolAddress = derivePool(baseMint, quoteMint);

        const baseVault = deriveBaseVault(baseMint, this.config);

        const quoteVault = deriveQuoteVault(quoteMint, this.config);

        return this.program.methods
            .refundToken()
            .accountsPartial({
                poolAuthority: this.poolAuthority,
                config: this.config,
                baseMint: baseMint,
                quoteMint: quoteMint,
                pool: poolAddress,
                baseVault: baseVault,
                quoteVault: quoteVault,
                inputTokenAccount: userTokenAccount,
                outputTokenAccount: outputTokenAccount,
                tokenBaseProgram: TOKEN_PROGRAM_ID,
                tokenQuoteProgram: TOKEN_PROGRAM_ID,
                payer: payer,
                systemProgram: SystemProgram.programId,
                eventAuthority: this.eventAuthority,
                program: CLAWLAB_PROGRAM_ID,
            })
            .instruction()
    }

    async RefundIx(payer: PublicKey,
        baseMint: PublicKey,
        quoteMint: PublicKey,
        userTokenAccount: PublicKey,
        outputTokenAccount: PublicKey,
    ): Promise<TransactionInstruction> {
        return this.refundTokenIx(
            payer,
            baseMint,
            quoteMint,
            userTokenAccount,
            outputTokenAccount,
        )
    }

    async RefundTx(params: RefundParams): Promise<Transaction> {

        const {
            payer,
            baseMint,
        } = params

        const quoteMint = NATIVE_MINT;

        const preInstructions: TransactionInstruction[] = []
        const postInstructions: TransactionInstruction[] = []

        const userTokenAccount = deriveUserTokenAccount(baseMint, payer);

        const { ataPubkey: quoteMintAta, ix: createQuoteMintAtaIx } = await getOrCreateATAInstruction(
            this.connection,
            quoteMint,
            payer,
            payer,
            true,
            TOKEN_PROGRAM_ID,
        );

        createQuoteMintAtaIx && preInstructions.push(createQuoteMintAtaIx)

        const refundIx = await this.refundTokenIx(
            payer,
            baseMint,
            quoteMint,
            userTokenAccount,
            quoteMintAta,
        )

        const unwrapSolIx = unwrapSOLInstruction(payer, payer)
        unwrapSolIx && postInstructions.push(unwrapSolIx)

        return new Transaction().add(...preInstructions, refundIx, ...postInstructions)
    }

}