import { PublicKey } from '@solana/web3.js'

import {
    CLAWLAB_PROGRAM_ID,
    METAPLEX_PROGRAM_ID,
    DAMM_V2_PROGRAM_ID,
} from '../constants'

const SEED = Object.freeze({
    POOL_AUTHORITY: 'pool_authority',
    EVENT_AUTHORITY: '__event_authority',
    CONFIG: 'config',
    POOL: 'pool',
    BASE_VAULT: 'base_vault',
    QUOTE_VAULT: 'quote_vault',
    USER_TOKEN_ACCOUNT: 'user_token_account',
    METADATA: 'metadata',
})

export function deriveConfig(): PublicKey {
    const [config] = PublicKey.findProgramAddressSync(
        [Buffer.from(SEED.CONFIG)],
        CLAWLAB_PROGRAM_ID
    );
    return config;
}

export function derivePoolAuthority(): PublicKey {
    const [poolAuthority] = PublicKey.findProgramAddressSync(
        [Buffer.from(SEED.POOL_AUTHORITY)],
        CLAWLAB_PROGRAM_ID
    );
    return poolAuthority;
}

export function deriveEventAuthority(): PublicKey {
    const [eventAuthority] = PublicKey.findProgramAddressSync(
        [Buffer.from(SEED.EVENT_AUTHORITY)],
        CLAWLAB_PROGRAM_ID
    );
    return eventAuthority;
}

export function derivePool(baseMint: PublicKey, quoteMint: PublicKey): PublicKey {
    const [pool] = PublicKey.findProgramAddressSync(
        [Buffer.from(SEED.POOL), baseMint.toBuffer(), quoteMint.toBuffer()],
        CLAWLAB_PROGRAM_ID
    );
    return pool;
}

export function deriveBaseVault(baseMint: PublicKey, config: PublicKey): PublicKey {
    const [vault] = PublicKey.findProgramAddressSync(
        [Buffer.from(SEED.BASE_VAULT), config.toBuffer(), baseMint.toBuffer()],
        CLAWLAB_PROGRAM_ID
    );
    return vault;
}

export function deriveQuoteVault(quoteMint: PublicKey, config: PublicKey): PublicKey {
    const [vault] = PublicKey.findProgramAddressSync(
        [Buffer.from(SEED.QUOTE_VAULT), config.toBuffer(), quoteMint.toBuffer()],
        CLAWLAB_PROGRAM_ID
    );
    return vault;
}

export function deriveUserTokenAccount(baseMint: PublicKey, user: PublicKey): PublicKey {
    const [userOutputTokenAccount] = PublicKey.findProgramAddressSync(
        [Buffer.from(SEED.USER_TOKEN_ACCOUNT), baseMint.toBuffer(), user.toBuffer(),],
        CLAWLAB_PROGRAM_ID
    );
    return userOutputTokenAccount;
}

export function deriveMintMetadata(baseMint: PublicKey): PublicKey {
    // Metadata program (Token Metadata Program)

    // Find metadata PDA
    const [mintMetadata] = PublicKey.findProgramAddressSync(
        [Buffer.from(SEED.METADATA), METAPLEX_PROGRAM_ID.toBuffer(), baseMint.toBuffer(),],
        METAPLEX_PROGRAM_ID
    );

    return mintMetadata;
}