import { Commitment, Connection, PublicKey } from '@solana/web3.js'
import { ClawlabProgram } from './program'

import {
    getAccountData,
} from '../helpers'

import {
    Config,
    PoolConfig,
} from '../types'

export class StateService extends ClawlabProgram {
    constructor(connection: Connection) {
        super(connection)
    }

    async getConfig(): Promise<Config> {
        return getAccountData<Config>(
            this.config,
            'config',
            this.program,
            this.connection.commitment
        )
    }

    async getPoolConfig(
        poolAddress: PublicKey | string
    ): Promise<PoolConfig> {
        return getAccountData<PoolConfig>(
            poolAddress,
            'poolConfig',
            this.program,
            this.connection.commitment
        )
    }
}