import {
    Commitment,
    Connection,
    PublicKey,
    TransactionInstruction,
} from '@solana/web3.js'

import {
    createClawlabProgram,
    getOrCreateATAInstruction,
    derivePoolAuthority,
    deriveEventAuthority,
    deriveConfig,
} from '../helpers'

import type { Program } from '@coral-xyz/anchor'
import type { Clawlab as ClawlabIDL } from '../idl/clawlab/idl'

export class ClawlabProgram {
    program: Program<ClawlabIDL>
    protected connection: Connection
    protected poolAuthority: PublicKey
    protected eventAuthority: PublicKey
    protected config: PublicKey

    constructor(connection: Connection) {
        const { program } = createClawlabProgram(connection)
        this.program = program
        this.connection = connection
        this.poolAuthority = derivePoolAuthority()
        this.eventAuthority = deriveEventAuthority()
        this.config = deriveConfig()
    }

    protected async prepareTokenAccounts(
        owner: PublicKey,
        payer: PublicKey,
        tokenAMint: PublicKey,
        tokenBMint: PublicKey,
        tokenAProgram: PublicKey,
        tokenBProgram: PublicKey
    ): Promise<{
        ataTokenA: PublicKey
        ataTokenB: PublicKey
        instructions: TransactionInstruction[]
    }> {
        const instructions: TransactionInstruction[] = []
        const [
            { ataPubkey: ataTokenA, ix: createAtaTokenAIx },
            { ataPubkey: ataTokenB, ix: createAtaTokenBIx },
        ] = await Promise.all([
            getOrCreateATAInstruction(
                this.connection,
                tokenAMint,
                owner,
                payer,
                true,
                tokenAProgram
            ),
            getOrCreateATAInstruction(
                this.connection,
                tokenBMint,
                owner,
                payer,
                true,
                tokenBProgram
            ),
        ])
        createAtaTokenAIx && instructions.push(createAtaTokenAIx)
        createAtaTokenBIx && instructions.push(createAtaTokenBIx)

        return { ataTokenA, ataTokenB, instructions }
    }

    /**
     * Get the underlying program instance
     * @returns The program instance
     */
    getProgram(): Program<ClawlabIDL> {
        return this.program
    }
}