import {
    Commitment,
    PublicKey,
    Transaction,
    TransactionInstruction,
    type Connection,
} from '@solana/web3.js'

import {
    ClaimFeeParams,
} from '../types'

import {
    CLAWLAB_PROGRAM_ID,
} from '../constants'

import {
    NATIVE_MINT,
    TOKEN_PROGRAM_ID,
} from '@solana/spl-token'
import { ClawlabProgram } from './program'
import {
    derivePool,
    deriveQuoteVault,
    unwrapSOLInstruction,
    getOrCreateATAInstruction,
} from '../helpers'
import { StateService } from './state'

export class CreatorService extends ClawlabProgram {
    private state: StateService

    constructor(connection: Connection) {
        super(connection)
        this.state = new StateService(connection)
    }

    private async claimCreatorFeeIx(
        payer: PublicKey,
        baseMint: PublicKey,
        quoteMint: PublicKey,
        outputTokenAccount: PublicKey,
    ): Promise<TransactionInstruction> {
        const poolAddress = derivePool(baseMint, quoteMint);

        const quoteVault = deriveQuoteVault(quoteMint, this.config);

        return this.program.methods
            .claimCreator()
            .accountsPartial({
                poolAuthority: this.poolAuthority,
                config: this.config,
                baseMint: baseMint,
                quoteMint: quoteMint,
                pool: poolAddress,
                quoteVault: quoteVault,
                tokenAccount: outputTokenAccount,
                tokenBaseProgram: TOKEN_PROGRAM_ID,
                tokenQuoteProgram: TOKEN_PROGRAM_ID,
                payer: payer,
                eventAuthority: this.eventAuthority,
                program: CLAWLAB_PROGRAM_ID,
            })
            .instruction()
    }

    async ClaimFeeIx(payer: PublicKey,
        baseMint: PublicKey,
        quoteMint: PublicKey,
        outputTokenAccount: PublicKey,
    ): Promise<TransactionInstruction> {
        return this.claimCreatorFeeIx(payer, baseMint, quoteMint, outputTokenAccount)
    }

    async ClaimFeeTx(params: ClaimFeeParams): Promise<Transaction> {
        const {
            payer,
            baseMint,
        } = params

        const quoteMint = NATIVE_MINT;

        const preInstructions: TransactionInstruction[] = []
        const postInstructions: TransactionInstruction[] = []

        const { ataPubkey: quoteMintAta, ix: createQuoteMintAtaIx } = await getOrCreateATAInstruction(
            this.connection,
            quoteMint,
            payer,
            payer,
            true,
            TOKEN_PROGRAM_ID,
        );

        createQuoteMintAtaIx && preInstructions.push(createQuoteMintAtaIx)

        const createPoolIx = await this.claimCreatorFeeIx(payer, baseMint, quoteMint, quoteMintAta)

        const unwrapSolIx = unwrapSOLInstruction(payer, payer)
        unwrapSolIx && postInstructions.push(unwrapSolIx)

        return new Transaction().add(...preInstructions, createPoolIx, ...postInstructions)
    }

}