import { Commitment, Connection } from '@solana/web3.js'
import {
    StateService,
    UserService,
    CreatorService,
    PoolService,
} from './services'

export class ClawlabClient {
    public state: StateService
    public user: UserService
    public creator: CreatorService
    public pool: PoolService
    public connection: Connection

    constructor(connection: Connection) {
        this.state = new StateService(connection)
        this.user = new UserService(connection)
        this.creator = new CreatorService(connection)
        this.pool = new PoolService(connection)
        
        this.connection = connection
    }

    static create(
        connection: Connection,
        commitment: Commitment = 'confirmed'
    ): ClawlabClient {
        return new ClawlabClient(connection)
    }
}
