import {
    Commitment,
    PublicKey,
    Transaction,
    TransactionInstruction,
    type Connection,
} from '@solana/web3.js'

import {
    ClaimTokenParams,
} from '../types'

import {
    CLAWLAB_PROGRAM_ID,
} from '../constants'

import {
    NATIVE_MINT,
    TOKEN_PROGRAM_ID,
} from '@solana/spl-token'

import { ClawlabProgram } from './program'

import {
    derivePool,
    deriveUserTokenAccount,
    getOrCreateATAInstruction,
} from '../helpers'

import { StateService } from './state'

export class UserService extends ClawlabProgram {
    private state: StateService

    constructor(connection: Connection) {
        super(connection)
        this.state = new StateService(connection)
    }

    private async claimUserTokenIx(
        payer: PublicKey,
        baseMint: PublicKey,
        quoteMint: PublicKey,
        inputTokenAccount: PublicKey,
        outputTokenAccount: PublicKey,
    ): Promise<TransactionInstruction> {
        const poolAddress = derivePool(baseMint, quoteMint);

        return this.program.methods
            .claimUserToken()
            .accountsPartial({
                poolAuthority: this.poolAuthority,
                baseMint: baseMint,
                quoteMint: quoteMint,
                pool: poolAddress,
                inputTokenAccount: inputTokenAccount,
                outputTokenAccount: outputTokenAccount,
                tokenBaseProgram: TOKEN_PROGRAM_ID,
                tokenQuoteProgram: TOKEN_PROGRAM_ID,
                payer: payer,
                eventAuthority: this.eventAuthority,
                program: CLAWLAB_PROGRAM_ID,
            })
            .instruction()
    }

    async ClaimTokenIx(payer: PublicKey,
        baseMint: PublicKey,
        quoteMint: PublicKey,
        inputTokenAccount: PublicKey,
        outputTokenAccount: PublicKey,
    ): Promise<TransactionInstruction> {
        return this.claimUserTokenIx(payer, baseMint, quoteMint, inputTokenAccount, outputTokenAccount)
    }

    async ClaimTokenTx(params: ClaimTokenParams): Promise<Transaction> {
        const {
            payer,
            baseMint,
        } = params

        const quoteMint = NATIVE_MINT;

        const userTokenAccount = deriveUserTokenAccount(baseMint, payer);

        const preInstructions: TransactionInstruction[] = []

        const { ataPubkey: baseMintAta, ix: createBaseMintAtaIx } = await getOrCreateATAInstruction(
            this.connection,
            baseMint,
            payer,
            payer,
            true,
            TOKEN_PROGRAM_ID,
        );

        createBaseMintAtaIx && preInstructions.push(createBaseMintAtaIx)

        const claimUserTokenIx = await this.claimUserTokenIx(payer, baseMint, quoteMint, userTokenAccount, baseMintAta)

        return new Transaction().add(...preInstructions, claimUserTokenIx)
    }

}